# Load the NYSE non-ETF stocks
import json

stockinfo_file = locals()['var_functions.query_db:16']
with open(stockinfo_file, 'r') as f:
    stockinfo = json.load(f)

# Create a dictionary mapping symbol to company description
company_descriptions = {stock['Symbol']: stock['Company Description'] for stock in stockinfo}

print('__RESULT__:')
print(json.dumps({
    'total_symbols': len(company_descriptions),
    'sample_symbols': list(company_descriptions.keys())[:10],
    'sample_descriptions': {k: company_descriptions[k] for k in list(company_descriptions.keys())[:3]}
}))

